document.addEventListener('DOMContentLoaded', () => {

    /* ==========================================
       1. SCROLL REVEAL (Intersection Observer)
       ========================================== */
    const observerOptions = {
        root: null,
        rootMargin: '0px',
        threshold: 0.15 
    };

    const observer = new IntersectionObserver((entries, observer) => {
        entries.forEach(entry => {
            if (entry.isIntersecting) {
                // A MAGIA ESTÁ AQUI: Remove a invisibilidade forçada pelo JS
                entry.target.style.opacity = ''; 
                
                // Adiciona a nossa classe CSS que tem os Keyframes
                entry.target.classList.add('animar-entrada');
                
                // Performance: Para de vigiar depois da animação acontecer a 1ª vez
                observer.unobserve(entry.target);
            }
        });
    }, observerOptions);

    // Seleciona todos os elementos no HTML que têm a classe 'revelar-scroll'
    document.querySelectorAll('.revelar-scroll').forEach((el) => {
        // Esconde o elemento inicialmente
        el.style.opacity = '0';
        observer.observe(el);
    });

    /* ==========================================
       2. BOTÕES MAGNÉTICOS (Micro-interação)
       ========================================== */
    const magneticButtons = document.querySelectorAll('.btn-branco, .btn-contorno');

    magneticButtons.forEach(btn => {
        btn.addEventListener('mousemove', (e) => {
            const position = btn.getBoundingClientRect();
            const x = e.clientX - position.left - position.width / 2;
            const y = e.clientY - position.top - position.height / 2;

            btn.style.transform = `translate(${x * 0.3}px, ${y * 0.5}px)`;
        });

        btn.addEventListener('mouseout', () => {
            btn.style.transform = 'translate(0px, 0px)';
            btn.style.transition = 'transform 0.5s cubic-bezier(0.175, 0.885, 0.32, 1.275)';
        });

        btn.addEventListener('mouseenter', () => {
            btn.style.transition = 'none';
        });
    });

    /* ==========================================
       3. ANO AUTOMÁTICO NO FOOTER
       ========================================== */
    const currentYearElement = document.getElementById('ano-atual');
    if (currentYearElement) {
        currentYearElement.textContent = new Date().getFullYear();
    }

});